function cmdStatus() {
    const indexContent = fs.existsSync(INDEX_FILE) ? fs.readFileSync(INDEX_FILE, 'utf8').trim() : '';
    console.log('Staged files:');
    if (!indexContent) {
        console.log('(none)');
    } else {
        const entries = indexContent.split('\n').filter(l => l.length > 0);
        for (const e of entries) {
            console.log(e);
        }
    }
}

function parseCommit(commitHash) {
    const commitFile = path.join(COMMITS_DIR, commitHash);
    if (!fs.existsSync(commitFile)) return null;
    const content = fs.readFileSync(commitFile, 'utf8');
    const lines = content.split('\n');
    let parent = '', timestamp = '', message = '';
    const files = {};
    let inFiles = false;
    for (const line of lines) {
        if (line.startsWith('parent: ')) { parent = line.substring(8); inFiles = false; }
        else if (line.startsWith('timestamp: ')) { timestamp = line.substring(11); inFiles = false; }
        else if (line.startsWith('message: ')) { message = line.substring(9); inFiles = false; }
        else if (line === 'files:') { inFiles = true; }
        else if (inFiles && line.length > 0) {
            const spaceIdx = line.lastIndexOf(' ');
            const fname = line.substring(0, spaceIdx);
            const hash = line.substring(spaceIdx + 1);
            files[fname] = hash;
        }
    }
    return { parent, timestamp, message, files };
}

function cmdDiff(hash1, hash2) {
    const c1 = parseCommit(hash1);
    const c2 = parseCommit(hash2);
    if (!c1 || !c2) {
        console.log('Invalid commit');
        process.exit(1);
    }
    const allFiles = new Set([...Object.keys(c1.files), ...Object.keys(c2.files)]);
    const sorted = [...allFiles].sort();
    for (const f of sorted) {
        const in1 = f in c1.files;
        const in2 = f in c2.files;
        if (!in1 && in2) {
            console.log(`Added: ${f}`);
        } else if (in1 && !in2) {
            console.log(`Removed: ${f}`);
        } else if (in1 && in2 && c1.files[f] !== c2.files[f]) {
            console.log(`Modified: ${f}`);
        }
    }
}

function cmdCheckout(commitHash) {
    if (!commitHash) {
        console.error('Usage: minigit checkout <commit_hash>');
        process.exit(1);
    }
    const commit = parseCommit(commitHash);
    if (!commit) {
        console.log('Invalid commit');
        process.exit(1);
    }
    for (const [fname, blobHash] of Object.entries(commit.files)) {
        const blobContent = fs.readFileSync(path.join(OBJECTS_DIR, blobHash));
        fs.writeFileSync(fname, blobContent);
    }
    fs.writeFileSync(HEAD_FILE, commitHash);
    fs.writeFileSync(INDEX_FILE, '');
    console.log(`Checked out ${commitHash}`);
}

function cmdReset(commitHash) {
    if (!commitHash) {
        console.error('Usage: minigit reset <commit_hash>');
        process.exit(1);
    }
    const commit = parseCommit(commitHash);
    if (!commit) {
        console.log('Invalid commit');
        process.exit(1);
    }
    fs.writeFileSync(HEAD_FILE, commitHash);
    fs.writeFileSync(INDEX_FILE, '');
    console.log(`Reset to ${commitHash}`);
}

